/**
 * @fileoverview Fieldset component logic.
 * @module module/Fieldset/index
 */

import { default as razyui } from '../../index.js';
import { DEFAULTS } from './constants.js';
import { setupDOM } from './view.js';

const Fieldset = class {
    #root   = null;
    #config = {};

    constructor(selector, config = {}) {
        const root = razyui(selector);
        if (!root.length) { console.warn('Fieldset: element not found \u2192', selector); return; }

        this.#root   = root;
        this.#config = { ...DEFAULTS, ...config };
        setupDOM(root);
    }

    get element() { return this.#root[0]; }

    /** No-op teardown for API consistency. */
    destroy() { this.#root = null; this.#config = null; }
};

export default Fieldset;
