/**
 * @fileoverview Fieldset view setup.
 * @module module/Fieldset/view
 */

import { CLS, PART } from './constants.js';

export function setupDOM(root) {
    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    root.find('.' + CLS.LEGEND).each(el => {
        PART.LEGEND.apply(el);
    });
    root.find('.' + CLS.DESCRIPTION).each(el => {
        PART.DESCRIPTION.apply(el);
    });
    root.find('.' + CLS.BODY).each(el => {
        PART.BODY.apply(el);
    });

    return {};
}
